Code.Terraform:
```hcl
resource "aws_backup_report_plan" "<example_resource_name>" {
  name = "<example_resource_name>" # 关键：创建至少一个报告计划

  report_delivery_channel {
    s3_bucket_name = "<example_resource_name>" # 关键：报告的目标存储桶
    formats        = ["CSV"] # 关键：有效的报告文件格式
  }

  report_setting {
    report_template = "BACKUP_JOB_REPORT" # 关键：最小作业报告模板
  }
}
```
